import java.util.Scanner;

public class SecureBuffer {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.println("Enter your name: ");
        String input = scanner.nextLine();

        // Limiting the buffer size to the length of user input or a maximum of 10 characters
        int bufferSize = Math.min(input.length(), 10);

        char[] buffer = new char[bufferSize];

        // Copying user input into the buffer with bounds checking
        input.getChars(0, bufferSize, buffer, 0);

        System.out.println("Hello, " + new String(buffer));
    }
}

